script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {sender.add_onResponseComplete(on$Filter$ResponseComplete);}
function set$Form$DefaultValue(f) {
  var v = f.grid._salesPriceType ? f.grid._salesPriceType : '';
  if (!v) f.setItemControlBehavior('loai_gia', f._salesPriceType, f._salesPriceTypeName, null);
    else f.setItemValue('kieu_gb', v);
  setValue$Filter$SalesPriceType(f, v);
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function setObjectFilterHidden(f, c, b) {
  var o = f.getItem(c);
  o.field.AllowNulls = !b;
  if (b) {
    var grandNode = o.parentNode.parentNode;
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
  if (!b) $common.setVisible(o.parentNode.parentNode.parentNode, false);
}
function onChange$Filter$SalesPriceType(o) {o.parentForm.request('SalesPriceType', 'SalesPriceType', ['loai_gia'], o);}
function addExternalSalesPriceTypeKey(f, k, c) {
  if (f.getItem(c).disabled) return;
  var v = $func.trim(f.getItemValue(c));
  if (v != '') Array.add(k, {Name: c, Opr: 'like', Value: v += '%', Type: 'String', Ignore: false});
}
function setObject$Filter$SalesPriceType(f, c, t, v) {
  var a = c.split(','), b = (t.indexOf(v) > -1);
  for (var i = 0; i < a.length; i++) {
    o = f.getItem($func.trim(a[i]));
    o.disabled = !b;
    f._setReadOnly(o, !b);
    if (!b) o.value = '';
  }
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array(), ref = $func.trim(f.getItem('ten_gb%l').value);
      g._salesPriceCode = f.getItemValue('loai_gia');
      g._salesPriceType = f.getItemValue('kieu_gb');

      Array.add(k, {Name: 'loai_gia', Opr: '=', Value: g._salesPriceCode, Type: 'String', Ignore: false});
      Array.add(k, {Name: 'ngay_ban', Opr: '>=', Value: f.getItemValue('ngay_ban'), Type: 'DateTime', Ignore: false});
      addExternalSalesPriceTypeKey(f, k, 'ma_kho');
      addExternalSalesPriceTypeKey(f, k, 'ma_kh');
      addExternalSalesPriceTypeKey(f, k, 'nh_kh1');
      addExternalSalesPriceTypeKey(f, k, 'nh_kh2');
      addExternalSalesPriceTypeKey(f, k, 'nh_kh3');
      addExternalSalesPriceTypeKey(f, k, 'nh_kh9');
      addExternalSalesPriceTypeKey(f, k, 'ma_vt');
      g.set_externalKey(k);
      g._alterTitle = [null, [['%s1', $func.trim(g._salesPriceCode), true], ['%s2', ref, true]]];

      var a = g._salesPriceType.split(',');
      if (a.length == 0) break;
      var t = a[0], l = g._language == 'v' ? '' : '2';
      g._hiddenFields = [
        {Fields: 'ma_kho', Value: !(t.indexOf('S') > -1)},
        {Fields: 'ma_kh, ten_kh' + l, Value: !(t.indexOf('C') > -1)},
        {Fields: 'nh_kh1, ten_nh_kh1' + l, Value: !(t.indexOf('D') > -1)},
        {Fields: 'nh_kh2, ten_nh_kh2' + l, Value: !(t.indexOf('E') > -1)},
        {Fields: 'nh_kh3, ten_nh_kh3' + l, Value: !(t.indexOf('F') > -1)},
        {Fields: 'nh_kh9, ten_nh_kh9' + l, Value: !(t.indexOf('G') > -1)}
      ];
      remove$GridReport$Filter(g);
      break;
    case 'SalesPriceType':
      f.setItemControlBehavior('kieu_gb', result[0].Value, null, true);
      var t = result[0].Value.split(',')[0];
      setValue$Filter$SalesPriceType(f, t);
      break;
    default:
      break;
  }
}
function setValue$Filter$SalesPriceType(f, t) {
  setObject$Filter$SalesPriceType(f, 'ma_kho, ten_kho%l', t, 'S');
  setObject$Filter$SalesPriceType(f, 'ma_kh, ten_kh%l', t, 'C');
  setObject$Filter$SalesPriceType(f, 'nh_kh1, ten_nh_kh1%l', t, 'D');
  setObject$Filter$SalesPriceType(f, 'nh_kh2, ten_nh_kh2%l', t, 'E');
  setObject$Filter$SalesPriceType(f, 'nh_kh3, ten_nh_kh3%l', t, 'F');
  setObject$Filter$SalesPriceType(f, 'nh_kh9, ten_nh_kh9%l', t, 'G');
}
/* </flatten> */
